  ('elementary-f29af906-moex-00832', 'elementary-f29af906', 'elementary-f29af906-moex-110-01c5eaab', 'sub-elementary-f29af906-05', NULL, 'single_choice', '「許多青春期訂交結盟的友誼，會使人在年事稍長之後，以互相交換陳舊回憶的方式，撫慰人們各自在生命 中遭遇到的種種創傷或失落；所謂□□□□、相忘於江湖。回憶，使回憶者當下的現實顯得不再那麼沉重， 也使逝去的現實顯得□□許多」，根據前後文意，選出□最適當者：', '["遺世獨立／悲戚", "相濡以沫／輕盈", "惶恐不安／虛幻", "劍拔弩張／深刻"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
